styles:
:root {
      --color-dark: #333;
      --color-green: #15b788;
      --color-blue: #1395ba;
      --color-bg: #feffff;
      --color-muted: #666;
      --color-border: #e8e8e8;
      --max-width: 1080px;
    }

    * { margin: 0; padding: 0; box-sizing: border-box; }

    html { scroll-behavior: smooth; }

    body {
      font-family: -apple-system, BlinkMacSystemFont, 'Hiragino Kaku Gothic ProN', 'Hiragino Sans', Meiryo, sans-serif;
      color: var(--color-dark);
      line-height: 1.8;
      background: var(--color-bg);
    }

    a { color: inherit; }

    /* ===== Nav ===== */
    .site-nav {
      position: fixed;
      top: 0;
      left: 0;
      right: 0;
      z-index: 100;
      background: rgba(254, 255, 255, 0.92);
      backdrop-filter: blur(12px);
      border-bottom: 1px solid var(--color-border);
      transition: box-shadow 0.2s;
    }
    .site-nav.scrolled { box-shadow: 0 2px 16px rgba(0,0,0,0.06); }
    .nav-inner {
      max-width: var(--max-width);
      margin: 0 auto;
      padding: 0 24px;
      height: 64px;
      display: flex;
      align-items: center;
      justify-content: space-between;
      gap: 24px;
    }
    .nav-logo {
      display: flex;
      align-items: center;
      gap: 10px;
      text-decoration: none;
      flex-shrink: 0;
    }
    .nav-logo img { height: 32px; width: auto; }
    .nav-links {
      display: flex;
      align-items: center;
      gap: 28px;
      list-style: none;
    }
    .nav-links a {
      text-decoration: none;
      font-size: 0.9rem;
      font-weight: 500;
      color: var(--color-muted);
      transition: color 0.2s;
    }
    .nav-links a:hover { color: var(--color-green); }
    .nav-toggle {
      display: none;
      background: none;
      border: none;
      cursor: pointer;
      padding: 8px;
    }
    .nav-toggle span {
      display: block;
      width: 22px;
      height: 2px;
      background: var(--color-dark);
      margin: 5px 0;
      transition: transform 0.2s;
    }

    /* ===== Hero ===== */
    .hero {
      background: var(--color-dark);
      color: var(--color-bg);
      padding: 140px 24px 100px;
      text-align: center;
      position: relative;
      overflow: hidden;
      min-height: 92vh;
      display: flex;
      align-items: center;
      justify-content: center;
    }
    #heroCanvas {
      position: absolute;
      inset: 0;
      width: 100%;
      height: 100%;
      z-index: 1;
      pointer-events: none;
    }
    .hero-bg {
      position: absolute;
      inset: -20%;
      z-index: 0;
      background:
        radial-gradient(ellipse 60% 50% at 20% 80%, rgba(21,183,136,0.22) 0%, transparent 70%),
        radial-gradient(ellipse 50% 40% at 80% 20%, rgba(19,149,186,0.18) 0%, transparent 70%);
      animation: gradientShift 12s ease-in-out infinite alternate;
    }
    .hero-vignette {
      position: absolute;
      inset: 0;
      z-index: 2;
      pointer-events: none;
      background:
        radial-gradient(ellipse 80% 70% at 50% 50%, transparent 30%, rgba(51,51,51,0.65) 100%);
    }
    @keyframes gradientShift {
      0% { transform: translate(0, 0) scale(1); }
      100% { transform: translate(3%, -2%) scale(1.05); }
    }
    .hero-inner {
      position: relative;
      z-index: 3;
      max-width: 820px;
      margin: 0 auto;
    }
    .hero-logo {
      height: 56px;
      width: auto;
      margin-bottom: 2rem;
      filter: drop-shadow(0 0 24px rgba(21,183,136,0.25));
    }
    .hero-slogan {
      min-height: 9.5rem;
      margin-bottom: 1.25rem;
    }
    .hero-slogan p {
      font-size: clamp(1.25rem, 3.5vw, 1.85rem);
      font-weight: 700;
      line-height: 1.65;
      letter-spacing: 0.01em;
      opacity: 0;
      transform: translateY(24px);
      transition: opacity 0.7s ease, transform 0.7s ease;
    }
    .hero-slogan p + p { margin-top: 0.5rem; }
    .hero-slogan p.visible {
      opacity: 1;
      transform: translateY(0);
      text-shadow: 0 0 40px rgba(21,183,136,0.15);
    }
    .hero-slogan p:last-child {
      font-size: clamp(1.05rem, 2.8vw, 1.45rem);
      font-weight: 500;
      color: rgba(254,255,255,0.88);
    }
    .hero-principle {
      font-size: 0.85rem;
      color: rgba(254,255,255,0.45);
      letter-spacing: 0.04em;
      margin-bottom: 2rem;
      opacity: 0;
      transition: opacity 0.6s ease 0.2s;
    }
    .hero-principle.visible { opacity: 1; }
    .hero-actions {
      display: flex;
      gap: 14px;
      justify-content: center;
      flex-wrap: wrap;
      opacity: 0;
      transform: translateY(16px);
      transition: opacity 0.6s ease, transform 0.6s ease;
    }
    .hero-actions.visible {
      opacity: 1;
      transform: translateY(0);
    }
    .btn {
      display: inline-block;
      padding: 12px 28px;
      border-radius: 8px;
      text-decoration: none;
      font-size: 0.95rem;
      font-weight: 600;
      transition: opacity 0.2s, transform 0.15s;
    }
    .btn:hover { opacity: 0.88; transform: translateY(-1px); }
    .btn-primary { background: var(--color-green); color: #fff; }
    .btn-outline {
      background: transparent;
      color: #fff;
      border: 1px solid rgba(255,255,255,0.35);
    }
    .hero-scroll {
      position: absolute;
      bottom: 28px;
      left: 50%;
      transform: translateX(-50%);
      z-index: 3;
      display: flex;
      flex-direction: column;
      align-items: center;
      gap: 6px;
      color: rgba(254,255,255,0.4);
      font-size: 0.7rem;
      letter-spacing: 0.15em;
      text-decoration: none;
      opacity: 0;
      animation: scrollHint 2s ease 2.8s forwards;
    }
    .hero-scroll span {
      display: block;
      width: 1px;
      height: 32px;
      background: linear-gradient(to bottom, rgba(21,183,136,0.8), transparent);
      animation: scrollLine 1.6s ease-in-out infinite;
    }
    @keyframes scrollHint {
      to { opacity: 1; }
    }
    @keyframes scrollLine {
      0%, 100% { transform: scaleY(0.4); opacity: 0.4; transform-origin: top; }
      50% { transform: scaleY(1); opacity: 1; transform-origin: top; }
    }

    /* ===== Sections ===== */
    section { padding: 88px 24px; }
    .section-alt { background: #f8f9fa; }
    .container { max-width: var(--max-width); margin: 0 auto; }

    .section-label {
      display: inline-block;
      font-size: 0.75rem;
      font-weight: 600;
      letter-spacing: 0.12em;
      text-transform: uppercase;
      color: var(--color-green);
      margin-bottom: 0.6rem;
    }
    .section-title {
      font-size: 1.75rem;
      font-weight: 700;
      margin-bottom: 1rem;
      letter-spacing: -0.02em;
    }
    .section-lead {
      color: var(--color-muted);
      font-size: 1rem;
      max-width: 640px;
      margin-bottom: 2.5rem;
    }

    /* ===== Reveal ===== */
    .reveal {
      opacity: 0;
      transform: translateY(20px);
      transition: opacity 0.6s ease, transform 0.6s ease;
    }
    .reveal.revealed {
      opacity: 1;
      transform: translateY(0);
    }

    /* ===== Vision ===== */
    .vision-grid {
      display: grid;
      grid-template-columns: repeat(3, 1fr);
      gap: 24px;
    }
    .vision-card.reveal {
      transform: translateY(20px);
    }
    .vision-card.reveal.revealed {
      transform: translateY(0);
    }
    .vision-card {
      background: #fff;
      border: 1px solid var(--color-border);
      border-radius: 16px;
      padding: 32px 28px;
      transition: border-color 0.25s, box-shadow 0.25s, opacity 0.6s ease, transform 0.6s ease;
      will-change: transform;
    }
    .vision-card:hover {
      border-color: rgba(21,183,136,0.4);
      box-shadow: 0 12px 40px rgba(21,183,136,0.12);
    }
    .vision-num {
      display: inline-block;
      font-size: 0.75rem;
      font-weight: 700;
      letter-spacing: 0.1em;
      color: var(--color-green);
      margin-bottom: 0.75rem;
    }
    .vision-card h3 {
      font-size: 1.15rem;
      font-weight: 700;
      margin-bottom: 0.75rem;
    }
    .vision-card p {
      font-size: 0.92rem;
      color: var(--color-muted);
      line-height: 1.75;
    }

    /* ===== Roadmap ===== */
    .roadmap-timeline {
      position: relative;
      max-width: 720px;
      margin: 0 auto;
      padding-left: 48px;
    }
    .roadmap-timeline::before {
      content: '';
      position: absolute;
      left: 15px;
      top: 8px;
      bottom: 8px;
      width: 2px;
      background: var(--color-border);
      transform-origin: top;
      transform: scaleY(0);
      transition: transform 1s ease;
    }
    .roadmap-timeline.revealed::before {
      transform: scaleY(1);
    }
    .roadmap-item {
      position: relative;
      padding-bottom: 40px;
      opacity: 0;
      transform: translateY(16px);
      transition: opacity 0.5s ease, transform 0.5s ease;
    }
    .roadmap-item:last-child { padding-bottom: 0; }
    .roadmap-item.revealed {
      opacity: 1;
      transform: translateY(0);
    }
    .roadmap-item::before {
      content: '';
      position: absolute;
      left: -40px;
      top: 8px;
      width: 12px;
      height: 12px;
      border-radius: 50%;
      background: var(--color-green);
      border: 3px solid var(--color-bg);
      box-shadow: 0 0 0 2px var(--color-green);
    }
    .roadmap-item.future::before {
      background: transparent;
      box-shadow: 0 0 0 2px var(--color-muted);
    }
    .roadmap-item.future .roadmap-label {
      color: var(--color-muted);
      border-color: var(--color-muted);
    }
    .roadmap-meta {
      display: flex;
      align-items: center;
      gap: 12px;
      margin-bottom: 0.4rem;
      flex-wrap: wrap;
    }
    .roadmap-label {
      font-size: 0.7rem;
      font-weight: 700;
      letter-spacing: 0.08em;
      text-transform: uppercase;
      color: var(--color-green);
      border: 1px solid var(--color-green);
      border-radius: 100px;
      padding: 2px 10px;
    }
    .roadmap-period {
      font-size: 0.8rem;
      color: var(--color-muted);
    }
    .roadmap-item h3 {
      font-size: 1.05rem;
      font-weight: 700;
      margin-bottom: 0.3rem;
    }
    .roadmap-item p {
      font-size: 0.9rem;
      color: var(--color-muted);
    }
    .roadmap-note {
      font-size: 0.82rem;
      color: var(--color-muted);
      margin-top: 0.25rem;
      opacity: 0.85;
    }

    /* ===== Purpose ===== */
    .purpose-details {
      border: 1px solid var(--color-border);
      border-radius: 12px;
      background: #fff;
      overflow: hidden;
    }
    .purpose-details summary {
      padding: 20px 24px;
      font-weight: 600;
      cursor: pointer;
      list-style: none;
      display: flex;
      align-items: center;
      justify-content: space-between;
      gap: 12px;
    }
    .purpose-details summary::-webkit-details-marker { display: none; }
    .purpose-details summary::after {
      content: '+';
      font-size: 1.25rem;
      color: var(--color-muted);
      transition: transform 0.2s;
    }
    .purpose-details[open] summary::after {
      content: '−';
    }
    .purpose-details .purpose-body {
      padding: 0 24px 24px;
      border-top: 1px solid var(--color-border);
    }
    .purpose-grid {
      display: grid;
      grid-template-columns: repeat(auto-fill, minmax(300px, 1fr));
      gap: 16px;
      padding-top: 20px;
    }
    .purpose-item {
      background: #f8f9fa;
      border: 1px solid var(--color-border);
      border-radius: 12px;
      padding: 22px 24px;
      display: flex;
      gap: 16px;
      align-items: flex-start;
    }
    .purpose-num {
      flex-shrink: 0;
      width: 32px;
      height: 32px;
      border-radius: 8px;
      background: linear-gradient(135deg, var(--color-green), var(--color-blue));
      color: #fff;
      font-size: 0.8rem;
      font-weight: 700;
      display: flex;
      align-items: center;
      justify-content: center;
    }
    .purpose-text { font-size: 0.92rem; line-height: 1.7; }

    /* ===== Services ===== */
    .services-grid {
      display: grid;
      grid-template-columns: repeat(auto-fill, minmax(220px, 1fr));
      gap: 20px;
    }
    .service-card {
      background: #fff;
      border: 1px solid var(--color-border);
      border-radius: 12px;
      padding: 28px 24px;
      text-align: center;
    }
    .service-icon {
      width: 64px;
      height: 64px;
      margin: 0 auto 14px;
      object-fit: contain;
    }
    .service-card h3 {
      font-size: 1rem;
      margin-bottom: 0.4rem;
    }
    .service-card p {
      font-size: 0.85rem;
      color: var(--color-muted);
    }

    /* ===== Products ===== */
    .products-grid {
      display: grid;
      grid-template-columns: repeat(auto-fill, minmax(320px, 1fr));
      gap: 24px;
    }
    .product-card {
      background: #fff;
      border: 1px solid var(--color-border);
      border-radius: 16px;
      padding: 28px;
      display: flex;
      flex-direction: column;
      transition: box-shadow 0.2s, border-color 0.2s;
    }
    .product-card:hover {
      box-shadow: 0 8px 32px rgba(0,0,0,0.07);
      border-color: rgba(21,183,136,0.3);
    }
    .product-thumb {
      width: 56px;
      height: 56px;
      border-radius: 12px;
      object-fit: cover;
      flex-shrink: 0;
      background: #f0f4f3;
    }
    .product-header {
      display: flex;
      align-items: flex-start;
      justify-content: space-between;
      gap: 12px;
      margin-bottom: 0.6rem;
    }
    .product-title-row {
      display: flex;
      align-items: center;
      gap: 12px;
      flex: 1;
      min-width: 0;
    }
    .product-card h3 {
      font-size: 1.2rem;
      font-weight: 700;
    }
    .product-badge {
      flex-shrink: 0;
      font-size: 0.7rem;
      font-weight: 600;
      padding: 3px 10px;
      border-radius: 100px;
      background: rgba(21,183,136,0.1);
      color: var(--color-green);
    }
    .product-desc {
      color: var(--color-muted);
      font-size: 0.9rem;
      flex: 1;
      margin-bottom: 1.25rem;
    }
    .product-links {
      display: flex;
      flex-wrap: wrap;
      gap: 10px;
      margin-top: auto;
    }
    .product-links a {
      display: inline-block;
      padding: 8px 18px;
      border-radius: 6px;
      text-decoration: none;
      font-size: 0.85rem;
      font-weight: 500;
      transition: opacity 0.2s;
    }
    .product-links a:hover { opacity: 0.8; }
    .link-main { background: var(--color-dark); color: #fff; }
    .link-privacy { background: var(--color-green); color: #fff; }
    .link-support { background: var(--color-blue); color: #fff; }
    .product-github {
      margin-top: 12px;
      font-size: 0.82rem;
    }
    .product-github a {
      color: var(--color-blue);
      text-decoration: none;
    }
    .product-github a:hover { text-decoration: underline; }

    /* ===== About ===== */
    .about-content {
      display: grid;
      grid-template-columns: 1fr 1fr;
      gap: 48px;
      align-items: center;
    }
    .about-text p {
      color: var(--color-muted);
      margin-bottom: 1rem;
      font-size: 0.95rem;
    }
    .about-visual {
      display: flex;
      align-items: center;
      justify-content: center;
      padding: 40px;
      background: #fff;
      border: 1px solid var(--color-border);
      border-radius: 16px;
    }
    .about-visual img {
      width: 100%;
      max-width: 320px;
      height: auto;
      border-radius: 12px;
    }

    /* ===== Footer ===== */
    footer {
      background: var(--color-dark);
      color: rgba(254,255,255,0.7);
      padding: 48px 24px 32px;
    }
    .footer-inner {
      max-width: var(--max-width);
      margin: 0 auto;
      display: grid;
      grid-template-columns: 1fr auto;
      gap: 32px;
      align-items: start;
    }
    .footer-brand img { height: 36px; margin-bottom: 12px; }
    .footer-brand p { font-size: 0.85rem; max-width: 320px; }
    .footer-nav {
      display: flex;
      gap: 48px;
    }
    .footer-nav h4 {
      font-size: 0.8rem;
      color: #fff;
      margin-bottom: 10px;
      letter-spacing: 0.05em;
    }
    .footer-nav ul { list-style: none; }
    .footer-nav li { margin-bottom: 6px; }
    .footer-nav a {
      font-size: 0.85rem;
      color: rgba(254,255,255,0.6);
      text-decoration: none;
      transition: color 0.2s;
    }
    .footer-nav a:hover { color: var(--color-green); }
    .footer-bottom {
      max-width: var(--max-width);
      margin: 32px auto 0;
      padding-top: 24px;
      border-top: 1px solid rgba(255,255,255,0.1);
      font-size: 0.8rem;
      text-align: center;
    }

    /* ===== Reduced motion ===== */
    @media (prefers-reduced-motion: reduce) {
      html { scroll-behavior: auto; }
      .hero-bg { animation: none; }
      .hero-scroll { animation: none; opacity: 1; }
      .hero-scroll span { animation: none; }
      .hero-slogan p,
      .hero-principle,
      .hero-actions,
      .reveal,
      .roadmap-item {
        opacity: 1 !important;
        transform: none !important;
        transition: none !important;
      }
      .roadmap-timeline::before {
        transform: scaleY(1) !important;
        transition: none !important;
      }
    }

    /* ===== Responsive ===== */
    @media (max-width: 768px) {
      .nav-links {
        display: none;
        position: absolute;
        top: 64px;
        left: 0;
        right: 0;
        flex-direction: column;
        background: #fff;
        padding: 16px 24px 24px;
        border-bottom: 1px solid var(--color-border);
        gap: 16px;
      }
      .nav-links.open { display: flex; }
      .nav-toggle { display: block; }
      .hero { padding: 120px 20px 80px; min-height: 85vh; }
      .hero-logo { height: 44px; }
      .hero-slogan { min-height: 11rem; }
      .vision-grid { grid-template-columns: 1fr; }
      .about-content { grid-template-columns: 1fr; }
      .footer-inner { grid-template-columns: 1fr; }
      .footer-nav { flex-direction: column; gap: 24px; }
      .products-grid { grid-template-columns: 1fr; }
      .roadmap-timeline { padding-left: 40px; }
      .roadmap-item::before { left: -33px; }
    }
